query:
PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s rdf:type ?o1 .
  ?s bsbm:productFeature ?o2 }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s rdf:type ?o1 .
  ?s bsbm:productFeature ?o2 }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s bsbm:rating1 ?o1 .
  ?s bsbm:rating3 ?o2 }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s rdf:type ?o1 .
  OPTIONAL { ?s bsbm:productFeature ?o2 } }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s bsbm:rating1 ?o1 .
  OPTIONAL { ?s bsbm:rating3 ?o2 } }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s bsbm:rating3 ?o1 .
  OPTIONAL { ?s bsbm:rating1 ?o2 } }

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX dc: <http://purl.org/dc/elements/1.1/>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s dc:publisher ?o1 .
  ?s rdf:type ?o2 .
  OPTIONAL {
  ?s dc:date ?o3 . }
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX dc: <http://purl.org/dc/elements/1.1/>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s dc:publisher ?o1 .
  OPTIONAL {
  ?s rdf:type ?o2 .
  ?s dc:date ?o3 . }
}

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?a bsbm:product ?b .
  ?b rdf:type ?c .
  OPTIONAL {
  ?c rdfs:comment ?d . }
}

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?a bsbm:product ?b .
  OPTIONAL {
  ?b rdf:type ?c .
  ?c rdfs:comment ?d . }
}

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s rdf:type ?o1 .
  MINUS { ?s bsbm:productFeature ?o2 } }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s bsbm:rating1 ?o1 .
  MINUS { ?s bsbm:rating3 ?o2 } }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s bsbm:rating3 ?o1 .
  MINUS { ?s bsbm:rating1 ?o2 } }

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX dc: <http://purl.org/dc/elements/1.1/>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s dc:publisher ?o1 .
  ?s rdf:type ?o2 .
  MINUS {
  ?s dc:date ?o3 . }
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX dc: <http://purl.org/dc/elements/1.1/>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s dc:publisher ?o1 .
  MINUS {
  ?s rdf:type ?o2 .
  ?s dc:date ?o3 . }
}

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?a bsbm:product ?b .
  ?b rdf:type ?c .
  MINUS {
  ?c rdfs:comment ?d . }
}

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?a bsbm:product ?b .
  MINUS {
  ?b rdf:type ?c .
  ?c rdfs:comment ?d . }
}

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s rdf:type ?o1 .
  FILTER EXISTS { ?s bsbm:productFeature ?o2 } }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s bsbm:rating3 ?o1 .
  FILTER EXISTS { ?s bsbm:rating1 ?o2 } }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s bsbm:rating1 ?o1 .
  FILTER EXISTS { ?s bsbm:rating3 ?o2 } }

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX dc: <http://purl.org/dc/elements/1.1/>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s dc:publisher ?o1 .
  ?s rdf:type ?o2 .
  FILTER EXISTS {
  ?s dc:date ?o3 . }
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX dc: <http://purl.org/dc/elements/1.1/>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?s dc:publisher ?o1 .
  FILTER EXISTS {
  ?s rdf:type ?o2 .
  ?s dc:date ?o3 . }
}

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?a bsbm:product ?b .
  ?b rdf:type ?c .
  FILTER EXISTS {
  ?c rdfs:comment ?d . }
}

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(*) AS ?count)
WHERE {
  ?a bsbm:product ?b .
  FILTER EXISTS {
  ?b rdf:type ?c .
  ?c rdfs:comment ?d . }
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX dc: <http://purl.org/dc/elements/1.1/>
SELECT (COUNT(*) AS ?count) WHERE {
  { ?s dc:publisher ?o1 }
  UNION { ?s rdf:type ?o1 }
  ?s dc:date ?o2
}

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT (COUNT(*) AS ?count) WHERE {
  { ?s bsbm:rating1 ?o1 }
  UNION { ?s rdf:type ?o1 }
  ?s bsbm:rating3 ?o2
}

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX dc: <http://purl.org/dc/elements/1.1/>
SELECT (COUNT(*) AS ?count) WHERE {
  { ?s rdf:type ?o1 }
  UNION { ?s dc:publisher ?o1 }
  ?s bsbm:productFeature ?o2
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX dc: <http://purl.org/dc/elements/1.1/>
SELECT (COUNT(*) AS ?count) WHERE {
  { ?s rdf:type ?o } UNION { ?s dc:publisher ?o }
  FILTER (?s = ?o)
}

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (COUNT(*) AS ?count) WHERE { 
  ?s bsbm:productPropertyNumeric5 ?o .
  ?s bsbm:productPropertyNumeric4 ?o }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
PREFIX dc: <http://purl.org/dc/elements/1.1/>
SELECT (COUNT(*) AS ?count) WHERE { 
  ?s dc:publisher ?o .
  ?s bsbm:vendor ?o }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT ?object (COUNT(?subject) AS ?count) {
?subject bsbm:deliveryDays ?object .
} GROUP BY ?object ORDER BY DESC(?count) LIMIT 10

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT ?object (COUNT(?subject) AS ?count) {
?subject bsbm:offerWebpage ?object .
} GROUP BY ?object ORDER BY DESC(?count) LIMIT 10

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT ?o1 (COUNT(?s) AS ?count) {
  ?s bsbm:deliveryDays ?o1 .
  ?s bsbm:offerWebpage ?o2 .
} GROUP BY ?o1 ORDER BY DESC(?count) LIMIT 10

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT ?o1 (COUNT(?s) AS ?count) (MIN(?s) AS ?min) (MAX(?s) AS ?max)
  (SAMPLE(?s) AS ?sample) {
  ?s bsbm:deliveryDays ?o1 .
  ?s bsbm:offerWebpage ?o2 .
} GROUP BY ?o1 ORDER BY DESC(?count) LIMIT 10

PREFIX dc: <http://purl.org/dc/elements/1.1/>
SELECT (SUM(STRLEN(?cat)) AS ?sum) {
{ SELECT (GROUP_CONCAT(?o; SEPARATOR=" ") AS ?cat) {
  ?s dc:title ?o. } GROUP BY ?s } }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (COUNT(DISTINCT ?object) AS ?count) {
  ?subject bsbm:deliveryDays ?object .
}

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (COUNT(DISTINCT ?object) AS ?count) {
?subject bsbm:offerWebpage ?object .
}

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (COUNT(DISTINCT ?o1) AS ?count) {
  ?s bsbm:deliveryDays ?o1 .
  ?s bsbm:offerWebpage ?o2 .
}

PREFIX bsbm_inst: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/instances/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(*) AS ?count) {
  bsbm_inst:ProductType263 rdfs:subClassOf+ ?o }

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(*) AS ?count) {
  ?s rdf:type/rdfs:subClassOf+ ?o }

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(*) AS ?count) {
  ?s rdf:type/rdfs:subClassOf+ ?o }

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(*) AS ?count)
WHERE { ?s rdfs:label ?o FILTER CONTAINS(?o, "com") }

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(*) AS ?count)
WHERE { ?s rdfs:label ?o FILTER REGEX(?o, "com") }

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(*) AS ?count)
WHERE { ?s rdfs:label ?o FILTER REGEX(?o, "c.m") }

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(*) AS ?count)
WHERE { ?s rdfs:label ?o FILTER REGEX(?o, "^C") }

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(*) AS ?count)
WHERE { ?s rdfs:label ?object FILTER REGEX(?object, "^Co") }

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (COUNT(*) AS ?count)
WHERE { ?s rdfs:label ?object FILTER REGEX(?object, "^Com") }

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (SUM(STRLEN(?o)) AS ?checksum)  {
  ?s rdfs:label ?o . }

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (SUM(STRLEN(STRBEFORE(?o, "a"))) AS ?checksum) {
  ?s rdfs:label ?o . }

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT (SUM(STRLEN(STRAFTER(?o, "a"))) AS ?checksum) {
  ?s rdfs:label ?o . }

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (SUM(xsd:integer(STRSTARTS(?o, "a"))) AS ?count) {
  ?s rdfs:label ?o . }

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (SUM(xsd:integer(STRENDS(?o, "a"))) AS ?count) {
  ?s rdfs:label ?o . }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (SUM(?o) AS ?sum)
WHERE { ?s bsbm:deliveryDays ?o }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (SUM(ABS(?o)) AS ?sum)
WHERE { ?s bsbm:deliveryDays ?o }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (SUM(CEIL(?o)) AS ?sum)
WHERE { ?s bsbm:deliveryDays ?o }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (SUM(FLOOR(?o)) AS ?sum)
WHERE { ?s bsbm:deliveryDays ?o }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (SUM(ROUND(?o)) AS ?sum)
WHERE { ?s bsbm:deliveryDays ?o }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (SUM(?o + ?o) AS ?sum)
WHERE { ?s bsbm:deliveryDays ?o }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (SUM(?o > 0) AS ?sum)
WHERE { ?s bsbm:deliveryDays ?o }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (COUNT(?s) AS ?count) {
  ?s bsbm:deliveryDays ?o .
  FILTER (?o >= 3) }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (COUNT(?s) AS ?count) {
  ?s bsbm:deliveryDays ?o .
  FILTER (?o >= 4) }

PREFIX bsbm: <http://www4.wiwiss.fu-berlin.de/bizer/bsbm/v01/vocabulary/>
SELECT (COUNT(?s) AS ?count) {
  ?s bsbm:deliveryDays ?o .
  FILTER (?o >= 6) }

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT (COUNT(?s) AS ?count) {
  ?s rdf:type ?o . FILTER (?s = ?o) }

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT (COUNT(?s) AS ?count) {
  ?s rdf:type ?o . FILTER (?s != ?o) }

PREFIX dc: <http://purl.org/dc/elements/1.1/>
SELECT (COUNT(?s) AS ?count) {
  ?s dc:title ?o . FILTER(LANG(?o) = "en") }

PREFIX dc: <http://purl.org/dc/elements/1.1/>
SELECT (SUM(YEAR(?o)) AS ?sum)
WHERE { ?s dc:date ?o }

PREFIX dc: <http://purl.org/dc/elements/1.1/>
SELECT (SUM(MONTH(?o)) AS ?sum)
WHERE { ?s dc:date ?o }

PREFIX dc: <http://purl.org/dc/elements/1.1/>
SELECT (SUM(DAY(?o)) AS ?sum)
WHERE { ?s dc:date ?o }
